// GitRm stages file deletions using git rm.
func (env *TestEnv) GitRm(paths ...string) {
	env.T.Helper()

	args := append([]string{"rm", "--"}, paths...)
	cmd := exec.Command("git", args...)
	cmd.Dir = env.RepoDir
	if output, err := cmd.CombinedOutput(); err != nil {
		env.T.Fatalf("git rm failed: %v\nOutput: %s", err, output)
	}
}

// GitCommitStagedWithShadowHooks commits whatever is already staged (without adding files first),
// running the prepare-commit-msg and post-commit hooks like a real workflow.
// Use this after GitRm or when files are already staged.
func (env *TestEnv) GitCommitStagedWithShadowHooks(message string) {
	env.T.Helper()
	env.gitCommitStagedWithShadowHooks(message, false)
}

// gitCommitStagedWithShadowHooks is the shared implementation for committing staged changes with hooks.
func (env *TestEnv) gitCommitStagedWithShadowHooks(message string, simulateTTY bool) {
	env.T.Helper()

	// Create a temp file for the commit message (prepare-commit-msg hook modifies this)
	msgFile := filepath.Join(env.RepoDir, ".git", "COMMIT_EDITMSG")
	if err := os.WriteFile(msgFile, []byte(message), 0o644); err != nil {
		env.T.Fatalf("failed to write commit message file: %v", err)
	}

	// Agent creates a file
	prompt := `Create a file called depleted.go with content:
package main
func Depleted() {}
Create only this file.`

	result, err := env.RunAgent(prompt)
	require.NoError(t, err)
	AssertAgentSuccess(t, result, err)
	require.True(t, env.FileExists("depleted.go"), "depleted.go should exist")

	// User commits the agent's file → gets checkpoint
	t.Log("Committing agent's file")
	env.GitCommitWithShadowHooks("Add depleted.go", "depleted.go")
	checkpointIDs := env.GetAllCheckpointIDsFromHistory()
	require.GreaterOrEqual(t, len(checkpointIDs), 1, "Should have checkpoint for agent's file")
	t.Logf("Checkpoint for agent's file: %s", checkpointIDs[0])

	// User manually edits the file (not from agent)
	env.WriteFile("depleted.go", "package main\n\n// Manual user edit\nfunc Depleted() { return }\n")

	// User commits the manual edit
	t.Log("Committing manual edit")
	env.GitCommitWithShadowHooks("Manual edit to depleted.go", "depleted.go")

	// This commit should NOT have a checkpoint (session is depleted, new edit is manual)
	allCheckpointIDs := env.GetAllCheckpointIDsFromHistory()
	if len(allCheckpointIDs) > len(checkpointIDs) {
		t.Logf("Manual edit got a checkpoint: %s (content-aware overlap may have matched)", allCheckpointIDs[0])
		// This is acceptable for modified files (always-overlap behavior),
		// but log it so we know
	} else {
		t.Log("Manual edit correctly has no checkpoint (session depleted)")
	}
}

env.GitAdd("controller.go")
env.GitCommit("Add MVC files")

sess := env.NewSession()

// Start session
